/**
 * @summary Export inspections to Excel
 */
export const getExportInspectionsUrl = (params?: ExportInspectionsParams,) => {
  const normalizedParams = new URLSearchParams();

  Object.entries(params || {}).forEach(([key, value]) => {

    if (value !== undefined) {
      normalizedParams.append(key, value === null ? 'null' : value.toString())
    }
  });

  const stringifiedParams = normalizedParams.toString();

  return stringifiedParams.length > 0 ? `/api/export/inspections?${stringifiedParams}` : `/api/export/inspections`
}

export const exportInspections = async (params?: ExportInspectionsParams, options?: RequestInit): Promise<Blob> => {

  return customFetch<Blob>(getExportInspectionsUrl(params),
  {
    ...options,
    method: 'GET'


  }
);}





export const getExportInspectionsQueryKey = (params?: ExportInspectionsParams,) => {
    return [
    `/api/export/inspections`, ...(params ? [params] : [])
    ] as const;
    }


export const getExportInspectionsQueryOptions = <TData = Awaited<ReturnType<typeof exportInspections>>, TError = ErrorType<unknown>>(params?: ExportInspectionsParams, options?: { query?:UseQueryOptions<Awaited<ReturnType<typeof exportInspections>>, TError, TData>, request?: SecondParameter<typeof customFetch>}
) => {

const {query: queryOptions, request: requestOptions} = options ?? {};

  const queryKey =  queryOptions?.queryKey ?? getExportInspectionsQueryKey(params);



    const queryFn: QueryFunction<Awaited<ReturnType<typeof exportInspections>>> = ({ signal }) => exportInspections(params, { signal, ...requestOptions });





   return  { queryKey, queryFn, ...queryOptions} as UseQueryOptions<Awaited<ReturnType<typeof exportInspections>>, TError, TData> & { queryKey: QueryKey }
}

export type ExportInspectionsQueryResult = NonNullable<Awaited<ReturnType<typeof exportInspections>>>
export type ExportInspectionsQueryError = ErrorType<unknown>


/**
 * @summary Export inspections to Excel
 */

export function useExportInspections<TData = Awaited<ReturnType<typeof exportInspections>>, TError = ErrorType<unknown>>(
 params?: ExportInspectionsParams, options?: { query?:UseQueryOptions<Awaited<ReturnType<typeof exportInspections>>, TError, TData>, request?: SecondParameter<typeof customFetch>}

 ):  UseQueryResult<TData, TError> & { queryKey: QueryKey } {

  const queryOptions = getExportInspectionsQueryOptions(params,options)

  const query = useQuery(queryOptions) as  UseQueryResult<TData, TError> & { queryKey: QueryKey };

  return { ...query, queryKey: queryOptions.queryKey };
}







